const item = $input.first().json;
const rawTweets = item.platform_angles.twitter || [];

// Validate and truncate tweets exceeding 280 characters
const tweets = rawTweets.map((tweet, index) => {
  const text = String(tweet).trim();
  if (text.length > 280) {
    console.warn(`Tweet ${index + 1} exceeds 280 chars (${text.length}) — truncating to 277 + '...'`);
    return text.substring(0, 277) + '...';
  }
  return text;
}).filter(t => t.length > 0);

if (tweets.length === 0) {
  throw new Error('No valid tweets after validation — all tweets were empty or invalid');
}

// Rate limit awareness log
// Free tier: 500 posts/month. Each tweet in a thread = 1 post.
console.log(`Twitter thread posting. Posts used: ${tweets.length} of 500 monthly allowance`);
console.log(`Monitor usage at: developer.twitter.com → your app → Rate Limits dashboard`);

return [{
  json: {
    content_bank_id: item.id,
    topic_title: item.topic_title,
    tweets: tweets,
    tweet_count: tweets.length,
    first_tweet: tweets[0],
    remaining_tweets: tweets.slice(1),
    has_remaining: tweets.length > 1,
    rate_limit_note: `Posts used this run: ${tweets.length} of 500 monthly allowance`
  }
}];

const firstTweetResponse = $input.first().json;
const validationData = $('Code: Validate and Format Tweet Array').item.json;

// Extract the tweet ID from the response
// Twitter API v2 returns: { data: { id: '...', text: '...' } }
const firstTweetId = firstTweetResponse.data && firstTweetResponse.data.id
  ? firstTweetResponse.data.id
  : null;

if (!firstTweetId) {
  throw new Error('Failed to get tweet ID from first tweet response — cannot chain thread replies');
}

// Construct the thread URL from the tweet ID
// Twitter thread URL format: https://x.com/username/status/tweetId
// We use a placeholder since we don't store the username in content_bank
const threadUrl = `https://x.com/i/web/status/${firstTweetId}`;

console.log(`First tweet posted. ID: ${firstTweetId}`);
console.log(`Thread URL: ${threadUrl}`);

return [{
  json: {
    content_bank_id: validationData.content_bank_id,
    topic_title: validationData.topic_title,
    first_tweet_id: firstTweetId,
    thread_url: threadUrl,
    remaining_tweets: validationData.remaining_tweets,
    tweet_count: validationData.tweet_count,
    has_remaining: validationData.has_remaining,
    rate_limit_note: validationData.rate_limit_note
  }
}];

// This node runs once per remaining tweet in the thread
// SplitInBatches feeds one item per batch — the item is the full data object
// We track the loop index to pick the correct tweet from remaining_tweets

const data = $input.first().json;
const batchIndex = $runIndex || 0;

// remaining_tweets is the array of tweets after the first one
const remainingTweets = data.remaining_tweets || [];
const currentTweet = remainingTweets[batchIndex];

if (!currentTweet) {
  throw new Error(`No tweet at batch index ${batchIndex} — remaining_tweets has ${remainingTweets.length} items`);
}

console.log(`Posting reply tweet ${batchIndex + 2} of ${data.tweet_count}: in_reply_to_tweet_id=${data.first_tweet_id}`);

return [{
  json: {
    content_bank_id: data.content_bank_id,
    first_tweet_id: data.first_tweet_id,
    thread_url: data.thread_url,
    remaining_tweets: remainingTweets,
    tweet_count: data.tweet_count,
    current_tweet_text: currentTweet,
    reply_to_tweet_id: data.first_tweet_id
  }
}];
